  rerankingModel?(modelId: string): RerankingModelV3;
}
```

---

### 6. IMAGE-ONLY PROVIDER EXAMPLE

**Black Forest Labs Provider Pattern** - A provider that ONLY supports image generation:

```typescript
export function createBlackForestLabs(
  options: BlackForestLabsProviderSettings = {}
): BlackForestLabsProvider {
  const baseURL = withoutTrailingSlash(options.baseURL ?? defaultBaseURL);
  const getHeaders = () => ...;

  const createImageModel = (modelId: BlackForestLabsImageModelId) =>
    new BlackForestLabsImageModel(modelId, {
      provider: 'black-forest-labs.image',
      baseURL,
      headers: getHeaders,
      fetch: options.fetch,
      pollIntervalMillis: options.pollIntervalMillis,
      pollTimeoutMillis: options.pollTimeoutMillis,
    });

  const embeddingModel = (modelId: string) => {
    throw new NoSuchModelError({
      modelId,
      modelType: 'embeddingModel',
    });
  };

  return {
    specificationVersion: 'v3',
    imageModel: createImageModel,
    image: createImageModel,
    languageModel: (modelId: string) => {
      throw new NoSuchModelError({
        modelId,
        modelType: 'languageModel',
      });
    },
    embeddingModel,
    textEmbeddingModel: embeddingModel,
  };
}

export const blackForestLabs = createBlackForestLabs();
```

**Key points for image-only providers:**
- Still must implement `ProviderV3` interface
- Throw `NoSuchModelError` for unsupported model types
- Only implement `imageModel()` and `image()` methods
- Still require `specificationVersion: 'v3'`

---

### 7. OPENAI PACKAGE EXPORTS

**File:** `/packages/openai/src/index.ts`

The main entry point exports:

```typescript
export { createOpenAI, openai } from './openai-provider';
export type { OpenAIProvider, OpenAIProviderSettings } from './openai-provider';

// Model options (for type hints)
export type { OpenAILanguageModelChatOptions } from './chat/...';
export type { OpenAIEmbeddingModelOptions } from './embedding/...';
// ... other model options

// Metadata types for provider-specific results
export type { OpenaiResponsesProviderMetadata, ... } from './responses/...';

export { VERSION } from './version';
```

**Pattern for image-only provider exports:**

```typescript
export { createBlackForestLabs, blackForestLabs } from './black-forest-labs-provider';
export type {
  BlackForestLabsProvider,
  BlackForestLabsProviderSettings,
} from './black-forest-labs-provider';
export type {
  BlackForestLabsImageModelId,
  BlackForestLabsAspectRatio,
} from './black-forest-labs-image-settings';
export type {
  BlackForestLabsImageModelOptions,
} from './black-forest-labs-image-model';
export { VERSION } from './version';
```

---

### 8. KEY IMPLEMENTATION PATTERNS

#### **OpenAI Image Model Implementation Structure:**

1. **API Request Handling** (using `postJsonToApi` / `postFormDataToApi` from provider-utils):
   - Combine headers with custom ones
   - Build request body with model-specific parameters
   - Handle form data for file uploads
   - Use failure/success response handlers

2. **Response Schema** (Zod validation):
   ```typescript
   export const openaiImageResponseSchema = lazySchema(() =>
     zodSchema(
       z.object({
         created: z.number().nullish(),
         data: z.array(
           z.object({
             b64_json: z.string(),
             revised_prompt: z.string().nullish(),
           })
         ),
         usage: z.object(...).nullish(),
         // ... other fields
       })
     )
   );
   ```

3. **Warning Generation:**
   - Create `SharedV3Warning` array for unsupported features
   - Examples: aspect ratio not supported, seed not supported

4. **Provider Metadata:**
   - Keyed by provider name: `{ openai: { images: [...] } }`
   - Include per-image metadata (revisedPrompt, created, quality, etc.)

5. **Usage Tracking:**
   - Optional token counts: inputTokens, outputTokens, totalTokens
   - Optional per-image token distribution

#### **Configuration Pattern:**

```typescript
interface OpenAIImageModelConfig extends OpenAIConfig {
  _internal?: {
    currentDate?: () => Date;
  };
}

type OpenAIConfig = {
  provider: string;
  url: (options: { modelId: string; path: string }) => string;
  headers: () => Record<string, string | undefined>;
  fetch?: FetchFunction;
};
```

#### **Provider Options Handling:**

```typescript
// In doGenerate:
{
  providerOptions: {
    openai: {
      style: "vivid",
      quality: "hd",
      response_format: "b64_json",
      // ... provider-specific options
    }
  }
}
```

---

### 9. COMPLETE PROVIDER SETUP CHECKLIST

For implementing a new image-only provider:

1. **Create package structure:**
   - `packages/my-provider/src/`
   - `packages/my-provider/package.json`
   - `packages/my-provider/tsconfig.json`
   - `packages/my-provider/tsup.config.ts`

2. **Core files needed:**
   - `my-provider.ts` - Image model implementation (implements ImageModelV3)
   - `my-provider-provider.ts` - Factory and provider interface
   - `my-provider-settings.ts` - Model IDs and aspect ratio types
   - `my-provider-options.ts` - Zod schema for provider-specific options
   - `my-provider-api.ts` - API response schemas
   - `index.ts` - Main exports
   - `version.ts` - Version string

3. **Dependencies:**
   ```json
   "dependencies": {
     "@ai-sdk/provider": "workspace:*",
     "@ai-sdk/provider-utils": "workspace:*"
   }
   ```

4. **Export structure:**
   - Default factory: `createMyProvider()`
   - Default singleton: `myProvider`
   - Provider interface type
   - Provider settings type
   - Model ID types
   - Model options types

5. **Test structure:**
   - Unit tests for image model
   - Unit tests for provider factory
   - Fixtures for API responses

---

### 10. USEFUL UTILITIES FROM PROVIDER-UTILS

Common utilities used in image implementations:

```typescript
import {
  combineHeaders,
  convertBase64ToUint8Array,
  convertToFormData,
  createJsonResponseHandler,
  downloadBlob,
  postFormDataToApi,
  postJsonToApi,
  getFromApi,
  createJsonErrorResponseHandler,
  createStatusCodeErrorResponseHandler,
  createBinaryResponseHandler,
  delay,
  resolve,
  lazySchema,
  parseProviderOptions,
} from '@ai-sdk/provider-utils';
```

---

### 11. VERSION HISTORY & V2 REFERENCE

**V2 vs V3 differences:**
- V2: `ImageModelV2CallWarning` type (different warning structure)
- V2: No usage support
- V3: `SharedV3Warning` type (unified warning system)
- V3: Optional `ImageModelV3Usage` support
- V3: Structured response metadata

Both versions follow the same basic implementation pattern, but V3 is recommended for new providers.

---

This comprehensive guide shows that implementing an image-generation-only provider requires:
1. A model class implementing `ImageModelV3`
2. A provider factory returning a `ProviderV3` instance
3. Type definitions for model IDs and options
4. API schema definitions using Zod
5. Proper package configuration and exports
6. Error handling and response validation

The architecture is clean and modular, allowing providers to be independent packages while sharing the common provider interface standard.

