import type { ImageModelV3, SharedV3Warning } from '@ai-sdk/provider';
import type { InferSchema, Resolvable } from '@ai-sdk/provider-utils';
import {
  FetchFunction,
  combineHeaders,
  createJsonErrorResponseHandler,
  createJsonResponseHandler,
  lazySchema,
  parseProviderOptions,
  postJsonToApi,
  resolve,
  zodSchema,
} from '@ai-sdk/provider-utils';
import { z } from 'zod/v4';
import type { PixelArtImageModelId } from './pixelart-image-settings';

interface PixelArtImageModelConfig {
  provider: string;
  baseURL: string;
  headers?: Resolvable<Record<string, string | undefined>>;
  fetch?: FetchFunction;
  _internal?: {
    currentDate?: () => Date;
  };
}

export class PixelArtImageModel implements ImageModelV3 {
  readonly specificationVersion = 'v3';
  readonly maxImagesPerCall = 4;

  get provider(): string {
    return this.config.provider;
  }

  constructor(
    readonly modelId: PixelArtImageModelId,
    private readonly config: PixelArtImageModelConfig,
  ) {}

  async doGenerate({
    prompt,
    n,
    size,
    aspectRatio,
    seed,
    providerOptions,
    headers,
    abortSignal,
  }: Parameters<ImageModelV3['doGenerate']>[0]): Promise<
    Awaited<ReturnType<ImageModelV3['doGenerate']>>
  > {
    const warnings: Array<SharedV3Warning> = [];

    if (aspectRatio) {
      warnings.push({
        type: 'unsupported',
        feature: 'aspectRatio',
        details:
          'PixelArt does not support aspectRatio. Use the size option instead.',
      });
    }

    const pixelartOptions = await parseProviderOptions({
      provider: 'pixelart',
      providerOptions,
      schema: pixelartImageModelOptionsSchema,
    });

    const body: Record<string, unknown> = {
      model: this.modelId,
      prompt,
      n,
      size: pixelartOptions?.size ?? size,
      style: pixelartOptions?.style ?? 'pixel',
      pixel_density: pixelartOptions?.pixelDensity,
      seed,
      response_format: 'b64_json',
    };

    const currentDate = this.config._internal?.currentDate?.() ?? new Date();
    const combinedHeaders = combineHeaders(
      await resolve(this.config.headers),
      headers,
    );

    const { value: response, responseHeaders } = await postJsonToApi({
      url: `${this.config.baseURL}/images/generations`,
      headers: combinedHeaders,
      body,
      failedResponseHandler: pixelartFailedResponseHandler,
      successfulResponseHandler: createJsonResponseHandler(
        pixelartImageResponseSchema,
      ),
      abortSignal,
      fetch: this.config.fetch,
    });

    return {
      images: response.data.map(
        (item: { b64_json: string }) => item.b64_json,
      ),
      warnings,
      providerMetadata: {
        pixelart: {
          images: response.data.map(
            (item: { style?: string; pixel_density?: number }) => ({
              ...(item.style != null && { style: item.style }),
              ...(item.pixel_density != null && {
                pixelDensity: item.pixel_density,
              }),
            }),
          ),
        },
      },
      response: {
        modelId: this.modelId,
        timestamp: currentDate,
        headers: responseHeaders,
      },
    };
  }
}

export const pixelartImageModelOptionsSchema = lazySchema(() =>
  zodSchema(
    z.object({
      /**
       * Image size, e.g. "512x512", "256x256".
       */
      size: z.string().optional(),

      /**
       * Art style for the generated image.
       */
      style: z.enum(['pixel', 'retro', '8bit']).optional(),

      /**
       * Pixel density of the generated image.
       * Higher values produce more detailed pixel art.
       */
      pixelDensity: z.number().min(1).max(16).optional(),
    }),
  ),
);

export type PixelArtImageModelOptions = InferSchema<
  typeof pixelartImageModelOptionsSchema
>;

const pixelartImageResponseSchema = lazySchema(() =>
  zodSchema(
    z.object({
      data: z.array(
        z.object({
          b64_json: z.string(),
          style: z.string().nullish(),
          pixel_density: z.number().nullish(),
        }),
      ),
    }),
  ),
);

const pixelartErrorSchema = z.object({
  error: z
    .object({
      message: z.string().optional(),
      type: z.string().optional(),
      code: z.string().optional(),
    })
    .optional(),
});

const pixelartFailedResponseHandler = createJsonErrorResponseHandler({
  errorSchema: pixelartErrorSchema,
  errorToMessage: error => {
    if (
      typeof error === 'object' &&
      error != null &&
      'error' in error &&
      typeof (error as Record<string, unknown>).error === 'object'
    ) {
      const errObj = (error as { error?: { message?: string } }).error;
      return errObj?.message ?? 'Unknown PixelArt error';
    }
    return 'Unknown PixelArt error';
  },
});

